import{_ as a,a as r}from"./chunks/listcontexmenu.BPReYXTv.js";import{_ as o,o as i,c as e,ae as l}from"./chunks/framework.C00B0EYs.js";const m=JSON.parse('{"title":"列表编辑器","description":"以表格视图编辑牵引与制动关键帧。","frontmatter":{"title":"列表编辑器","description":"以表格视图编辑牵引与制动关键帧。"},"headers":[],"relativePath":"zh/docs/guide/list-editor.md","filePath":"zh/docs/guide/list-editor.md"}'),s={name:"zh/docs/guide/list-editor.md"};function n(d,t,c,h,p,g){return i(),e("div",null,[...t[0]||(t[0]=[l('<h1 id="列表编辑器" tabindex="-1">列表编辑器 <a class="header-anchor" href="#列表编辑器" aria-label="Permalink to &quot;列表编辑器&quot;">​</a></h1><p>图表编辑器是主要创作界面，但不是唯一入口。Motor Sound Editor 同时提供 <strong>列表编辑器（List Editor）</strong>，用于以表格方式处理关键帧数据。</p><p>当你需要批量查看、校对或精确输入大量关键帧时，列表编辑器会比图形化曲线提供更直接的数据反馈。</p><p><img src="'+a+'" alt="列表视图"></p><h2 id="_1-核心功能" tabindex="-1">1. 核心功能 <a class="header-anchor" href="#_1-核心功能" aria-label="Permalink to &quot;1. 核心功能&quot;">​</a></h2><p>列表编辑器会把当前轨道的关键帧映射成表格内容。通过这种方式，你可以像处理电子表格一样管理声音数据。</p><ul><li><strong>精确输入</strong>：可以直接输入具体数值，例如 <code>60.5 km/h</code> 或 <code>0.85</code>。</li><li><strong>全局总览</strong>：在一个视图中查看当前轨道的关键帧分布，更容易发现突跳和冗余点。</li><li><strong>双工况并排编辑</strong>：当前实现会同时显示 <strong>Traction</strong> 和 <strong>Brake</strong> 两组数据，并分别列出 Pitch 与 Volume。</li></ul><h2 id="_2-界面组成" tabindex="-1">2. 界面组成 <a class="header-anchor" href="#_2-界面组成" aria-label="Permalink to &quot;2. 界面组成&quot;">​</a></h2><p>表格主要由以下区域构成：</p><ol><li><strong>Traction 区域</strong>：包含牵引模式下的速度与数值列。</li><li><strong>Brake 区域</strong>：包含制动模式下的速度与数值列。</li><li><strong>Pitch / Volume 列</strong>：分别对应音高与音量关键帧。</li></ol><h2 id="_3-关键特性" tabindex="-1">3. 关键特性 <a class="header-anchor" href="#_3-关键特性" aria-label="Permalink to &quot;3. 关键特性&quot;">​</a></h2><h3 id="草稿式编辑" tabindex="-1">草稿式编辑 <a class="header-anchor" href="#草稿式编辑" aria-label="Permalink to &quot;草稿式编辑&quot;">​</a></h3><p>列表编辑器采用草稿式编辑流程：</p><ul><li>在列表中修改内容时，变更先停留在弹窗内部。</li><li>点击 <strong>Apply</strong> 后，变更才会正式写回项目。</li><li>点击 <strong>Cancel</strong> 则会放弃当前草稿。</li></ul><h3 id="自动排序" tabindex="-1">自动排序 <a class="header-anchor" href="#自动排序" aria-label="Permalink to &quot;自动排序&quot;">​</a></h3><p>关键帧会始终按速度从小到大排序。当你修改某个关键帧的速度后，列表中的行序可能自动重排，以保持逻辑顺序一致。</p><h2 id="_4-右键上下文菜单" tabindex="-1">4. 右键上下文菜单 <a class="header-anchor" href="#_4-右键上下文菜单" aria-label="Permalink to &quot;4. 右键上下文菜单&quot;">​</a></h2><p>无论是在图表工作区还是列表编辑器中，你都可以通过右键呼出上下文菜单，快速执行常用操作。</p><p><img src="'+r+'" alt="右键上下文菜单"></p><p>当前列表编辑器中的常见右键操作包括：</p><ul><li><strong>同步 traction 到 brake / 同步 brake 到 traction</strong>：将一侧数据复制到另一侧。</li><li><strong>添加关键帧</strong>：快速插入新的关键帧，并自动参与排序。</li><li><strong>删除当前关键帧</strong>：移除当前选中的关键帧。</li></ul>',21)])])}const b=o(s,[["render",n]]);export{m as __pageData,b as default};
